  "band_sh_press": {"id":"band_sh_press","name":"Press de hombro con banda","group":"hombro","modes":["peso"],"level":"Inicial","sets":"3","reps":"10–12","rest":"60s","tags":["empuje vertical","banda"],"cues":["Banda pisada, manos a la altura de los hombros","Empujá vertical hasta estirar","Costillas abajo, sin arquear la lumbar","Bajá con control a los hombros"],"errors":["Arquear la zona lumbar al empujar","Empujar hacia adelante en vez de arriba","Encoger el cuello"],"notes":"Empuje vertical dosificable."},
