  "bicycle_crunch": {"id":"bicycle_crunch","name":"Bicycle Crunch","group":"core","modes":["sinpeso"],"level":"Inicial","sets":"3","reps":"10–16 c/lado","rest":"45s","tags":["oblicuos","abdomen","core"],"cues":["Boca arriba con manos suaves detrás de la cabeza","Acercá hombro y rodilla contrarios sin tirar del cuello","Extendé la otra pierna sin perder abdomen activo","Alterná lento y parejo"],"errors":["Tirar fuerte de la nuca","Apurar el movimiento sin rotar el torso","Arquear la lumbar al extender pierna"],"notes":"Crunch alternado para abdomen y oblicuos."},
  "burpee": {"id":"burpee","name":"Burpee","group":"core","modes":["sinpeso"],"level":"Avanzado","sets":"3","reps":"5–8","rest":"90s","tags":["impacto","avanzado"],"cues":["Bajá con control a la plancha, sin tirarte","Plancha sólida antes de volver","Salto chico o sin salto según tolerancia","Ritmo que permita técnica constante"],"errors":["Quebrar la lumbar al bajar al piso","Aterrizar rígido del salto","Sumar velocidad perdiendo forma"],"notes":"Avanzado, no sugerido al inicio."},
  "rot_expl": {"id":"rot_expl","name":"Rotaciones explosivas","group":"core","modes":["peso","sinpeso"],"level":"Avanzado","sets":"3","reps":"6–8 c/lado","rest":"90s","tags":["rotación","pádel","avanzado"],"cues":["Cadera y torso giran juntos","Girá con fuerza y frená con control","Pies pivotando con el giro","Empezá lento y sumá velocidad de a poco"],"errors":["Girar solo con los brazos","Frenar en seco con la lumbar","Cargar de más el primer día"],"notes":"Transferencia a pádel, fase posterior."},
  "back_squat": {"id":"back_squat","name":"Sentadilla libre con barra","group":"pierna","modes":["peso"],"level":"Progresivo","sets":"3–4","reps":"6–10","rest":"90–120s","tags":["sentadilla","barra","cuádriceps"],"cues":["Barra firme sobre trapecios y pies al ancho cómodo","Descendé con rodillas siguiendo la línea de los pies","Empujá el piso para subir manteniendo el torso firme"],"errors":["Perder la curva lumbar abajo","Dejar colapsar las rodillas hacia dentro"],"notes":"Base de fuerza de piernas; progresá la carga de forma gradual."},
